// ✅ AO 프롬프트 조립기 — P1 원문 100% 보존 + files[] 통합 구조
const job = $input.first().json;

const p1 = job.prompt_p1 || '';

// files 파싱 (DB에는 clips 컬럼에 저장됨)
let files = [];
try {
  files = typeof job.clips === 'string' ? JSON.parse(job.clips) : (job.clips || []);
} catch(e) { files = []; }

const slotValues = {
  TOPIC: job.topic || '',
  KEYWORDS: job.keywords || '',
  CATEGORY: job.category || '',
  LANG: job.prompt_lang_detected || 'ko',
  ASPECT_RATIO: '9:16'
};

const finalPrompt = p1
  .replace(/\{TOPIC\}/g, slotValues.TOPIC)
  .replace(/\{KEYWORDS\}/g, slotValues.KEYWORDS)
  .replace(/\{CATEGORY\}/g, slotValues.CATEGORY)
  .replace(/\{LANG\}/g, slotValues.LANG)
  .replace(/\{ASPECT_RATIO\}/g, slotValues.ASPECT_RATIO);

// 모든 파일의 분석 결과를 수집 (유/무 관계없이 전부)
const analysisParts = [];
files.forEach((f, i) => {
  if (f.vision_analysis) analysisParts.push(`[Image ${i+1}: ${f.vision_analysis}]`);
  if (f.video_analysis) analysisParts.push(`[Video ${i+1}: ${f.video_analysis}]`);
});

// P1이 없으면 topic + keywords + 분석 결과로 자동 프롬프트 생성
let basePrompt = finalPrompt;
if (!p1) {
  const autoParts = [];
  if (job.topic) autoParts.push(`Create a cinematic video about: ${job.topic}`);
  if (job.keywords) autoParts.push(`Keywords: ${job.keywords}`);
  if (job.category) autoParts.push(`Category: ${job.category}`);
  basePrompt = autoParts.join('. ') + '. High quality, smooth motion, professional cinematography.';
}

const promptWithAnalysis = analysisParts.length > 0
  ? analysisParts.join('\n') + '\n' + basePrompt
  : basePrompt;

return [{
  json: {
    ...job,
    files: files,
    clip_duration: job.clip_duration || 8,
    prompt_to_engine: promptWithAnalysis,
    prompt_p1_preserved: p1 || null,
    prompt_auto_generated: !p1,
    assembled_at: new Date().toISOString()
  }
}];

