const prev = $('번역 필요 여부').first().json;
const translated = $input.first().json;

const promptEn = translated.content?.[0]?.text || prev.prompt_to_engine;

return [{
  json: {
    ...prev,
    prompt_en: promptEn
  }
}];

// ✅ Creatomate 최종 영상 합성 — ai_video / slideshow 분기
const job = $input.first().json;
const productionMode = job.production_mode || 'ai_video';
const scenes = job.scene_results || [];
const apiKey = $env.CREATOMATE_API_KEY;

if (scenes.length === 0) throw new Error('scene_results가 비어있음');

let elements = [];

if (productionMode === 'slideshow') {
  // ===== SLIDESHOW: NCA FFmpeg 합성 (onca 방식) =====
  const imgUrls = job.slide_image_urls || [];
  const audioUrl = job.tts_audio_url;
  const audioDuration = job.tts_duration || job.total_duration;
  const timestamps = job.tts_timestamps || [];
  const ttsText = (job.tts_text || '').replace(/<[^>]*>?/gm, '');
  const imgDur = job.img_duration || (audioDuration / imgUrls.length);
  const totalDuration = audioDuration;
  const BGM_URL = 'http://76.13.182.180:9000/audio/bgm_new.mp3';
  const SFX_URL = 'http://76.13.182.180:9000/audio/sfx_ppook.wav';

  function esc(t) {
    if (!t) return '';
    return t.replace(/[\u{1F600}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu,'').trim()
      .replace(/\\/g,'\\\\').replace(/'/g,'\u2019').replace(/"/g,'\u201D')
      .replace(/:/g,'\\:').replace(/;/g,'\;').replace(/,/g,'\\,')
      .replace(/\[/g,'\\[').replace(/\]/g,'\\]').replace(/\n/g,' ');
  }
  function wrap(t, max) {
    if (!t || t.replace(/\s+/g,'').length <= max) return t || '';
    const mid = Math.floor(t.length / 2);
    let best = -1, minD = t.length;
    for (let i = 1; i < t.length - 1; i++) {
      if (t[i] === ' ' && Math.abs(i - mid) < minD) { minD = Math.abs(i - mid); best = i; }
    }
    return best > 0 ? t.substring(0, best).trim() + '\n' + t.substring(best).trim() : t;
  }

  // subtitle segments from timestamps
  let subs = [];
  if (timestamps.length > 0) {
    for (const ts of timestamps) subs.push({ text: ts.text, start: ts.offset, duration: ts.duration });
  } else {
    const sentences = ttsText.split(/[.!?\u3002]+/).filter(s => s.trim());
    const segDur = totalDuration / Math.max(sentences.length, 1);
    sentences.forEach((s, i) => subs.push({ text: s.trim(), start: i * segDur, duration: segDur }));
  }

  let inputs = [];
  let idx = 0;
  const mediaIdx = [];

  for (const url of imgUrls) {
    inputs.push({ file_url: url, options: [{ option: '-loop', argument: '1' }, { option: '-framerate', argument: '30' }, { option: '-t', argument: imgDur.toFixed(2) }] });
    mediaIdx.push(idx++);
  }
  const audioIdx = idx;
  inputs.push({ file_url: audioUrl, options: [] }); idx++;
  const bgmIdx = idx;
  inputs.push({ file_url: BGM_URL, options: [{ option: '-stream_loop', argument: '-1' }] }); idx++;
  const sfxList = [];
  for (let i = 1; i < imgUrls.length; i++) {
    inputs.push({ file_url: SFX_URL, options: [] });
    sfxList.push({ idx: idx, ms: Math.round(i * imgDur * 1000) }); idx++;
  }

  let fp = [];
  for (let i = 0; i < imgUrls.length; i++) {
    fp.push(`[${mediaIdx[i]}:v]scale=1080:1080:force_original_aspect_ratio=increase,crop=1080:1080,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,fps=30[v${i}]`);
  }
  fp.push(`${imgUrls.map((_,i) => `[v${i}]`).join('')}concat=n=${imgUrls.length}:v=1:a=0[vconcat]`);

  fp.push(`[${audioIdx}:a]atrim=duration=${audioDuration.toFixed(2)},asetpts=PTS-STARTPTS[tts_raw]`);
  fp.push(`[${bgmIdx}:a]atrim=duration=${totalDuration.toFixed(2)},asetpts=PTS-STARTPTS,afade=t=out:st=${Math.max(0, totalDuration - 2).toFixed(2)}:d=2[bgm]`);

  if (sfxList.length > 0) {
    sfxList.forEach((s, i) => fp.push(`[${s.idx}:a]atrim=duration=0.3,asetpts=PTS-STARTPTS,volume=0.6,adelay=${s.ms}|${s.ms}[sfx${i}]`));
    fp.push(`${sfxList.map((_,i) => `[sfx${i}]`).join('')}amix=inputs=${sfxList.length}:duration=longest:normalize=0[sfx_mix]`);
    fp.push(`[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 1 0.8:normalize=0[amain]`);
  } else {
    fp.push(`[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 1:normalize=0[amain]`);
  }

  let ov = '[vconcat]null';
  for (const sub of subs) {
    const st = esc(wrap(sub.text, 12));
    if (!st) continue;
    ov += `,drawtext=expansion=none:text='${st}':fontsize=70:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:borderw=4:bordercolor=black:enable='between(t,${sub.start.toFixed(2)},${(sub.start + sub.duration).toFixed(2)})'`;
  }
  ov += '[vfinal]';
  fp.push(ov);

  const payload = {
    inputs,
    filters: [{ filter: fp.join(';') }],
    outputs: [{ options: [
      { option: '-map', argument: '[vfinal]' }, { option: '-map', argument: '[amain]' },
      { option: '-c:v', argument: 'libx264' }, { option: '-preset', argument: 'fast' }, { option: '-crf', argument: '23' },
      { option: '-c:a', argument: 'aac' }, { option: '-b:a', argument: '192k' },
      { option: '-pix_fmt', argument: 'yuv420p' }, { option: '-movflags', argument: '+faststart' },
      { option: '-t', argument: totalDuration.toFixed(2) }
    ], file_name: 'ao_slideshow.mp4' }]
  };

  const ncaResp = await this.helpers.httpRequest({
    method: 'POST', url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: { 'x-api-key': 'nca-sagong-2026', 'Content-Type': 'application/json' },
    body: payload, json: true, timeout: 600000
  });

  let videoUrl = '';
  if (Array.isArray(ncaResp.response)) videoUrl = ncaResp.response[0]?.file_url || '';
  else if (typeof ncaResp.response === 'string') videoUrl = ncaResp.response;
  else videoUrl = ncaResp.output_url || ncaResp.url || ncaResp.video_url || '';
  if (!videoUrl) throw new Error('NCA 영상 URL 없음: ' + JSON.stringify(ncaResp).substring(0, 500));

  return [{ json: { id: 'nca-slideshow', status: 'succeeded', url: videoUrl } }];
} else {
  // ===== AI_VIDEO: 기존 씬별 클립 이어붙이기 (변경 없음) =====
  const dur = parseInt(job.clip_duration) <= 4 ? 4 : 8;
  scenes.forEach((s, i) => {
    elements.push({
      type: 'video',
      source: s.video_url,
      time: i * dur,
      duration: dur,
      fit: 'cover'
    });
    if (s.audio_url) {
      elements.push({
        type: 'audio',
        source: s.audio_url,
        time: i * dur,
        duration: dur
      });
    }
  });
}

const body = {
  source: {
    output_format: 'mp4',
    width: 1080,
    height: 1920,
    elements: elements
  }
};

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.creatomate.com/v1/renders',
  headers: {
    'Authorization': `Bearer ${apiKey}`,
    'Content-Type': 'application/json'
  },
  body: body,
  json: true
});

const render = Array.isArray(resp) ? resp[0] : resp;
return [{ json: render }];

// NCA slideshow: 이미 완료, 폴링 불필요
const renderResponse = $input.first().json;
if (renderResponse.status === 'succeeded' && renderResponse.url) {
  const prevData = $('멀티씬 순차 처리').first().json;
  return [{ json: { ...prevData, rendered_video_url: renderResponse.url, render_id: renderResponse.id || 'nca' } }];
}
// Creatomate 렌더 폴링 (ai_video만 해당)
const renderId = renderResponse.id || (Array.isArray(renderResponse) ? renderResponse[0]?.id : null);
if (!renderId) throw new Error('renderId 없음');

const apiKey = $env.CREATOMATE_API_KEY || '';
let status = 'planned';
let url = null;
let attempts = 0;
const maxAttempts = 60;

while (!['succeeded', 'failed'].includes(status) && attempts < maxAttempts) {
  await new Promise(r => setTimeout(r, 5000));
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.creatomate.com/v1/renders/${renderId}`,
    headers: { 'Authorization': `Bearer ${apiKey}` },
    json: true
  });
  status = resp.status;
  url = resp.url;
  attempts++;
}

if (status !== 'succeeded' || !url) {
  throw new Error(`영상 렌더링 실패: ${status}`);
}

// ✅ TTS 폴링 출력에서 job 원본 데이터 병합
const prevData = $('멀티씬 순차 처리').first().json;
return [{
  json: {
    ...prevData,
    rendered_video_url: url,
    render_id: renderId
  }
}];

// ✅ 에러 핸들러 — 재시도 로직
const error = $input.first().json;
const jobId = $('큐에서 Job 꺼내기').first().json?.id;

if (!jobId) return [];

return [{
  json: {
    job_id: jobId,
    error_message: error.message || JSON.stringify(error),
    timestamp: new Date().toISOString()
  }
}];

// ✅ 영상/슬라이드쇼 처리 — production_mode 분기
const job = $input.first().json;
const productionMode = job.production_mode || 'ai_video';
let files = job.files || [];
if (typeof files === 'string') { try { files = JSON.parse(files); } catch(e) { files = []; } }

const directFiles = files.filter(f => f.use_directly !== false);
const apiKey = $env.KIEAI_API_KEY;
const promptBase = job.prompt_en || job.prompt_to_engine || job.prompt_p1;

// kie.ai 폴링 (공통)
async function pollTask(taskId) {
  for (let i = 0; i < 90; i++) {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
      headers: { 'Authorization': `Bearer ${apiKey}` },
      json: true
    });
    const state = resp?.data?.state;
    if (state === 'success') {
      const result = JSON.parse(resp.data.resultJson || '{}');
      return result.resultUrls?.[0] || null;
    }
    if (state === 'failed' || state === 'fail') {
      throw new Error(`Task 실패: ${resp.data.failMsg || state}`);
    }
    await new Promise(r => setTimeout(r, 10000));
  }
  throw new Error('Task 타임아웃 (900초)');
}

// TTS 생성 (공통)
async function generateTTS(text) {
  if (!text) return null;
  const ttsResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: {
      model: 'elevenlabs/text-to-speech-multilingual-v2',
      input: { text: text, voice_id: 'EXAVITQu4vr4xnSDxMaL' }
    },
    json: true
  });
  const ttsTaskId = ttsResp?.data?.taskId;
  if (ttsTaskId) return await pollTask.call(this, ttsTaskId);
  return null;
}

// 이미지 URL 수집
const imageUrls = directFiles
  .filter(f => f.type === 'image' && f.url)
  .map(f => f.url);

// ===== SLIDESHOW 모드 (edge-tts + NCA FFmpeg) =====
if (productionMode === 'slideshow') {
  if (imageUrls.length === 0) throw new Error('slideshow 모드: 이미지가 없습니다');
  const ttsText = (job.prompt_p1 || job.topic || '').replace(/<[^>]*>?/gm, '');
  if (!ttsText) throw new Error('slideshow: 나레이션 텍스트 없음');

  // edge-tts 나레이션 생성
  const ttsResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://172.17.0.1:5100/tts',
    headers: { 'Content-Type': 'application/json' },
    body: { text: ttsText, voice_id: 'tc_6059dad0b83880769a50502f', emotion: 'happy', tempo: 1.2 },
    json: true,
    timeout: 60000
  });
  const audioUrl = ttsResp.audio_url;
  const audioDuration = ttsResp.duration_sec;
  const timestamps = ttsResp.timestamps || [];
  if (!audioUrl) throw new Error('edge-tts audio_url 없음: ' + JSON.stringify(ttsResp).substring(0, 300));

  const imgDuration = audioDuration / imageUrls.length;

  return [{
    json: {
      ...job,
      production_mode: 'slideshow',
      slide_image_urls: imageUrls,
      tts_audio_url: audioUrl,
      tts_duration: audioDuration,
      tts_timestamps: timestamps,
      tts_text: ttsText,
      img_duration: imgDuration,
      scene_results: imageUrls.map((url, i) => ({
        index: i, image_url: url, start: i * imgDuration, duration: imgDuration, type: 'slide'
      })),
      total_scenes: imageUrls.length,
      total_duration: audioDuration
    }
  }];
}

// ===== AI_VIDEO 모드 (기존 Kling 3.0 — 변경 없음) =====
if (directFiles.length === 0) {
  if (!job.prompt_p1 && !job.prompt_to_engine) throw new Error('파일과 프롬프트 모두 없음');
}

const rawDur = parseInt(job.clip_duration) || 8;
const duration = String(Math.max(3, Math.min(15, rawDur)));

const klingInput = {
  prompt: promptBase,
  aspect_ratio: '9:16',
  mode: 'std',
  sound: false,
  duration: duration,
  multi_shots: false
};

if (imageUrls.length > 0) {
  klingInput.image_urls = imageUrls.slice(0, 2);
}

let taskResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.kie.ai/api/v1/jobs/createTask',
  headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
  body: { model: 'kling-3.0/video', input: klingInput },
  json: true
});

if (taskResp?.code !== 200 && klingInput.image_urls) {
  delete klingInput.image_urls;
  taskResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: { model: 'kling-3.0/video', input: klingInput },
    json: true
  });
}

const klingTaskId = taskResp?.data?.taskId;
if (!klingTaskId) throw new Error('Kling taskId 없음: ' + JSON.stringify(taskResp).substring(0, 200));

const videoUrl = await pollTask.call(this, klingTaskId);
if (!videoUrl) throw new Error('Kling 영상 URL 없음');

const audioUrl = await generateTTS.call(this, job.topic);

const sceneResults = [{
  index: 0,
  video_url: videoUrl,
  file_urls: imageUrls,
  audio_url: audioUrl,
  model: 'kling-3.0/video'
}];

return [{
  json: {
    ...job,
    production_mode: 'ai_video',
    scene_results: sceneResults,
    total_scenes: 1,
    total_duration: parseInt(duration)
  }
}];

/* === 기존 Seedance 코드 (보존) ===
// ... Seedance polling + TTS ...
=== 기존 Seedance 코드 끝 === */

// ✅ YouTube 업로드 — OAuth token refresh + chunked upload
const job = $input.first().json;
const videoUrl = job.rendered_video_url;
if (!videoUrl) throw new Error('rendered_video_url 없음');

// 1) OAuth 토큰 갱신
const tokenResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=refresh_token&client_id=${$env.YT_CLIENT_ID}&client_secret=${$env.YT_CLIENT_SECRET}&refresh_token=${$env.YT_REFRESH_TOKEN}`,
  json: true
});
const accessToken = tokenResp.access_token;
if (!accessToken) throw new Error('YouTube token refresh 실패');

// 2) 영상 크기 확인
const headResp = await this.helpers.httpRequest({
  method: 'HEAD',
  url: videoUrl,
  returnFullResponse: true
});
const contentLength = headResp.headers?.['content-length'] || '0';

const title = job.metadata?.title || job.topic || 'AO 자동 생성 영상';
const description = job.metadata?.description || [job.topic, job.keywords].filter(Boolean).join(' - ');
const tags = job.metadata?.tags || (job.keywords ? job.keywords.split(',').map(t => t.trim()) : []);

// 3) Resumable upload 초기화
const initResp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://www.googleapis.com/upload/youtube/v3/videos?uploadType=resumable&part=snippet,status',
  headers: {
    'Authorization': `Bearer ${accessToken}`,
    'Content-Type': 'application/json; charset=UTF-8',
    'X-Upload-Content-Length': contentLength,
    'X-Upload-Content-Type': 'video/mp4'
  },
  body: { snippet: { title, description, tags, categoryId: '22' }, status: { privacyStatus: 'unlisted' } },
  json: true,
  returnFullResponse: true
});

const uploadUrl = initResp.headers?.location;
if (!uploadUrl) throw new Error('resumable URL 없음');

// 4) 영상 다운로드 (Buffer)
const videoResp = await this.helpers.httpRequest({
  method: 'GET',
  url: videoUrl,
  encoding: null,
  returnFullResponse: true
});
const videoBuffer = videoResp.body;

// 5) PUT 업로드 — Node.js https 모듈 사용 (EPIPE 우회)
const https = require('https');
const url = require('url');

const uploadResult = await new Promise((resolve, reject) => {
  const parsed = new URL(uploadUrl);
  const options = {
    hostname: parsed.hostname,
    path: parsed.pathname + parsed.search,
    method: 'PUT',
    headers: {
      'Content-Type': 'video/mp4',
      'Content-Length': videoBuffer.length
    }
  };

  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try { resolve(JSON.parse(data)); }
      catch(e) { resolve({ raw: data }); }
    });
  });

  req.on('error', reject);
  req.write(videoBuffer);
  req.end();
});

const youtubeId = uploadResult?.id;
const youtubeUrl = youtubeId ? `https://youtube.com/watch?v=${youtubeId}` : null;

if (!youtubeId) throw new Error('YouTube 업로드 실패: ' + JSON.stringify(uploadResult).substring(0, 200));

return [{
  json: {
    ...job,
    youtube_video_id: youtubeId,
    youtube_url: youtubeUrl
  }
}];

// ✅ 웹앱 콜백 — 성공 (uploaded)
const job = $input.first().json;
const productionId = job.production_id;
const callbackUrl = $env.WEBAPP_CALLBACK_URL;

if (!productionId || !callbackUrl) {
  // production_id 또는 콜백 URL 없으면 스킵
  return [{ json: { ...job, callback_sent: false, reason: 'no production_id or callback_url' } }];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${callbackUrl}/api/productions/callback`,
    headers: { 'Content-Type': 'application/json' },
    body: {
      productionId: productionId,
      status: 'uploaded',
      youtubeVideoId: job.youtube_video_id || null,
      youtubeUrl: job.youtube_url || null,
      renderedVideoUrl: job.rendered_video_url || null,
      jobId: job.id
    },
    json: true
  });
  return [{ json: { ...job, callback_sent: true } }];
} catch(e) {
  // 콜백 실패해도 파이프라인은 성공으로 유지
  return [{ json: { ...job, callback_sent: false, callback_error: e.message } }];
}

// ✅ 웹앱 콜백 — 실패/재시도
const result = $input.first().json;
const jobId = result.id || result.job_id;
const status = result.status; // 'failed' or 'queued' (retry)
const callbackUrl = $env.WEBAPP_CALLBACK_URL;

// production_id는 원본 job에서 가져옴
const originalJob = $('큐에서 Job 꺼내기').first().json;
const productionId = originalJob?.production_id;

if (!productionId || !callbackUrl) {
  return [{ json: { ...result, callback_sent: false } }];
}

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${callbackUrl}/api/productions/callback`,
    headers: { 'Content-Type': 'application/json' },
    body: {
      productionId: productionId,
      status: status,
      error: result.last_error || $('에러 캡처').first().json?.error_message || null,
      retryCount: result.retry_count || 0,
      jobId: jobId
    },
    json: true
  });
  return [{ json: { ...result, callback_sent: true } }];
} catch(e) {
  return [{ json: { ...result, callback_sent: false, callback_error: e.message } }];
}

// ✅ AO 프롬프트 조립기 — P1 원문 100% 보존 + files[] 통합 구조
const job = $input.first().json;

const p1 = job.prompt_p1 || '';

// files 파싱 (DB에는 clips 컬럼에 저장됨)
let files = [];
try {
  files = typeof job.clips === 'string' ? JSON.parse(job.clips) : (job.clips || []);
} catch(e) { files = []; }

const slotValues = {
  TOPIC: job.topic || '',
  KEYWORDS: job.keywords || '',
  CATEGORY: job.category || '',
  LANG: job.prompt_lang_detected || 'ko',
  ASPECT_RATIO: '9:16'
};

const finalPrompt = p1
  .replace(/\{TOPIC\}/g, slotValues.TOPIC)
  .replace(/\{KEYWORDS\}/g, slotValues.KEYWORDS)
  .replace(/\{CATEGORY\}/g, slotValues.CATEGORY)
  .replace(/\{LANG\}/g, slotValues.LANG)
  .replace(/\{ASPECT_RATIO\}/g, slotValues.ASPECT_RATIO);

// 모든 파일의 분석 결과를 수집 (유/무 관계없이 전부)
const analysisParts = [];
files.forEach((f, i) => {
  if (f.vision_analysis) analysisParts.push(`[Image ${i+1}: ${f.vision_analysis}]`);
  if (f.video_analysis) analysisParts.push(`[Video ${i+1}: ${f.video_analysis}]`);
});

// P1이 없으면 topic + keywords + 분석 결과로 자동 프롬프트 생성
let basePrompt = finalPrompt;
if (!p1) {
  const autoParts = [];
  if (job.topic) autoParts.push(`Create a cinematic video about: ${job.topic}`);
  if (job.keywords) autoParts.push(`Keywords: ${job.keywords}`);
  if (job.category) autoParts.push(`Category: ${job.category}`);
  basePrompt = autoParts.join('. ') + '. High quality, smooth motion, professional cinematography.';
}

const promptWithAnalysis = analysisParts.length > 0
  ? analysisParts.join('\n') + '\n' + basePrompt
  : basePrompt;

return [{
  json: {
    ...job,
    files: files,
    clip_duration: job.clip_duration || 8,
    prompt_to_engine: promptWithAnalysis,
    prompt_p1_preserved: p1 || null,
    prompt_auto_generated: !p1,
    assembled_at: new Date().toISOString()
  }
}];

